publish.value:
{%- set updated = CTX.all_known_folders | list -%}
{%- for created in CTX.created_folders_at_depth | default([]) -%}
  {%- if created is mapping and created.result is defined and created.result.result is defined and created.result.result.folder is defined -%}
    {%- set _ = updated.append(created.result.result.folder) -%}
  {%- endif -%}
{%- endfor -%}
{{ updated }}

with.items:
{%- set folders_at_depth = CTX.folders_to_create | selectattr('depth', 'equalto', CTX.current_depth) | list -%}
{%- set result = [] -%}
{%- for folder in folders_at_depth -%}
  {%- set entry = {'company_id': folder.company_id, 'company_name': folder.company_name, 'folder_name': folder.folder_name, 'folder_description': folder.folder_description} -%}
  {%- if folder.parent_folder_name is defined -%}
    {%- set parent_matches = CTX.all_known_folders | selectattr('name', 'equalto', folder.parent_folder_name) | selectattr('company_id', 'equalto', folder.company_id) | list -%}
    {%- if parent_matches | length > 0 -%}
      {%- set _ = entry.update({'parent_folder_id': parent_matches[0].id}) -%}
    {%- endif -%}
  {%- endif -%}
  {%- set _ = result.append(entry) -%}
{%- endfor -%}
{{ result }}

