{%- set result = [] -%}
{%- set all_existing_folders = [] -%}
{%- for item in CTX.company_folders -%}
  {%- if item is mapping and item.result is defined and item.result.result is defined -%}
    {%- for folder in item.result.result -%}
      {%- if folder is mapping and folder.name is defined -%}
        {%- set _ = all_existing_folders.append(folder) -%}
      {%- endif -%}
    {%- endfor -%}
  {%- endif -%}
{%- endfor -%}
{%- set existing_names = all_existing_folders | map(attribute='name') | list -%}
{# Recursive function to flatten folder hierarchy with depth #}
{%- macro flatten_folders(folders, parent_name, depth) -%}
  {%- for folder in folders -%}
    {%- if folder.name not in existing_names -%}
      {%- set folder_entry = {'name': folder.name, 'description': folder.description | default(''), 'depth': depth} -%}
      {%- if parent_name -%}
        {%- set _ = folder_entry.update({'parent_folder_name': parent_name}) -%}
      {%- endif -%}
      {%- set _ = result.append(folder_entry) -%}
    {%- endif -%}
    {%- if folder.children is defined -%}
      {%- set _ = flatten_folders(folder.children, folder.name, depth + 1) -%}
    {%- endif -%}
  {%- endfor -%}
{%- endmacro -%}
{# Flatten the folder definitions - use set to discard return value #}
{%- set _ = flatten_folders(CTX.folder_definitions, none, 0) -%}
{# Add company info to each folder #}
{%- set final_result = [] -%}
{%- for company in CTX.active_companies -%}
  {%- for folder in result -%}
    {%- set entry = {'company_id': company.id, 'company_name': company.name, 'folder_name': folder.name, 'folder_description': folder.description, 'depth': folder.depth} -%}
    {%- if folder.parent_folder_name is defined -%}
      {%- set _ = entry.update({'parent_folder_name': folder.parent_folder_name}) -%}
    {%- endif -%}
    {%- set _ = final_result.append(entry) -%}
  {%- endfor -%}
{%- endfor -%}
{{ final_result }}
